/**
 * Integration tests for the analytics pipeline.
 *
 * Tests the full path: RouteRequest → Route Handler → AnalyticsService → Repositories → Database
 * with realistic data and end-to-end verification of response shapes and values.
 */

import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { OrderRepository } from '../../src/repositories/order.repository.js';
import { UserRepository } from '../../src/repositories/user.repository.js';
import { AnalyticsService } from '../../src/services/analytics.service.js';
import { createAnalyticsRoutes } from '../../src/routes/analytics.routes.js';
import type { RouteRequest } from '../../src/routes/types.js';
import type { Order } from '../../src/models/order.js';
import type { User } from '../../src/models/user.js';

// --- Helpers ---

let idCounter = 0;

function makeOrder(overrides: Partial<Order> = {}): Order {
  idCounter++;
  return {
    id: `order-${String(idCounter).padStart(3, '0')}`,
    userId: 'user-001',
    items: [
      { productId: 'prod-1', name: 'Widget', quantity: 1, unitPrice: 25 },
    ],
    total: 25,
    status: 'confirmed',
    createdAt: new Date('2025-03-15'),
    updatedAt: new Date('2025-03-15'),
    ...overrides,
  };
}

function makeUser(overrides: Partial<User> = {}): User {
  idCounter++;
  return {
    id: `user-${String(idCounter).padStart(3, '0')}`,
    email: `user${idCounter}@example.com`,
    name: `User ${idCounter}`,
    role: 'member',
    createdAt: new Date('2025-01-01'),
    updatedAt: new Date('2025-01-01'),
    ...overrides,
  };
}

function req(query: Record<string, string> = {}): RouteRequest {
  return { params: {}, query };
}

// --- Test suites ---

describe('Analytics Pipeline Integration', () => {
  let db: Database;
  let orderRepo: OrderRepository;
  let userRepo: UserRepository;
  let service: AnalyticsService;
  let routes: ReturnType<typeof createAnalyticsRoutes>;

  beforeEach(() => {
    idCounter = 0;
    db = new Database();
    orderRepo = new OrderRepository(db);
    userRepo = new UserRepository(db);
    service = new AnalyticsService(orderRepo, userRepo);
    routes = createAnalyticsRoutes(service);
  });

  // =========================================================================
  // Full dashboard end-to-end
  // =========================================================================
  describe('Dashboard end-to-end', () => {
    beforeEach(() => {
      // 3 users across different dates and roles
      userRepo.save(makeUser({ id: 'u1', role: 'admin', createdAt: new Date('2025-01-10'), updatedAt: new Date('2025-01-10') }));
      userRepo.save(makeUser({ id: 'u2', role: 'member', createdAt: new Date('2025-02-05'), updatedAt: new Date('2025-02-05') }));
      userRepo.save(makeUser({ id: 'u3', role: 'viewer', createdAt: new Date('2025-03-20'), updatedAt: new Date('2025-03-20') }));

      // Orders spanning Jan–Mar
      orderRepo.save(makeOrder({
        id: 'o1', userId: 'u1', total: 100, status: 'delivered',
        items: [{ productId: 'p1', name: 'Alpha', quantity: 2, unitPrice: 50 }],
        createdAt: new Date('2025-01-15'), updatedAt: new Date('2025-01-15'),
      }));
      orderRepo.save(makeOrder({
        id: 'o2', userId: 'u2', total: 60, status: 'confirmed',
        items: [{ productId: 'p2', name: 'Beta', quantity: 3, unitPrice: 20 }],
        createdAt: new Date('2025-02-10'), updatedAt: new Date('2025-02-10'),
      }));
      orderRepo.save(makeOrder({
        id: 'o3', userId: 'u1', total: 200, status: 'shipped',
        items: [
          { productId: 'p1', name: 'Alpha', quantity: 1, unitPrice: 50 },
          { productId: 'p3', name: 'Gamma', quantity: 5, unitPrice: 30 },
        ],
        createdAt: new Date('2025-03-01'), updatedAt: new Date('2025-03-01'),
      }));
      orderRepo.save(makeOrder({
        id: 'o4', userId: 'u2', total: 40, status: 'cancelled',
        items: [{ productId: 'p2', name: 'Beta', quantity: 2, unitPrice: 20 }],
        createdAt: new Date('2025-02-20'), updatedAt: new Date('2025-02-20'),
      }));
    });

    it('returns all dashboard sections with correct data for a full date range', () => {
      const res = routes.getDashboard(req({
        startDate: '2025-01-01',
        endDate: '2025-03-31',
      }));

      expect(res.status).toBe(200);
      const data = res.data!;

      // Order metrics — all 4 orders in range
      expect(data.orderMetrics.totalOrders).toBe(4);
      expect(data.orderMetrics.totalRevenue).toBe(400);
      expect(data.orderMetrics.averageOrderValue).toBe(100);
      expect(data.orderMetrics.ordersByStatus.cancelled).toBe(1);
      expect(data.orderMetrics.ordersByStatus.delivered).toBe(1);

      // User metrics — all 3 users, all created in range
      expect(data.userMetrics.totalUsers).toBe(3);
      expect(data.userMetrics.newUsersInPeriod).toBe(3);
      expect(data.userMetrics.usersByRole).toEqual({ admin: 1, member: 1, viewer: 1 });

      // Time series should have data points spanning Jan 1 – Mar 31
      expect(data.revenueTimeSeries.metric).toBe('revenue');
      expect(data.revenueTimeSeries.dataPoints.length).toBe(90); // 90 days
      expect(data.ordersTimeSeries.metric).toBe('orderCount');

      // Top products — cancelled order excluded, so p2 counts only from o2
      expect(data.topProducts.length).toBe(3);
      // Alpha: 2*50 + 1*50 = 150, Gamma: 5*30 = 150, Beta: 3*20 = 60
      const alphaOrGamma = data.topProducts[0].name;
      expect(['Alpha', 'Gamma']).toContain(alphaOrGamma);
      expect(data.topProducts[2].name).toBe('Beta');
      expect(data.topProducts[2].totalRevenue).toBe(60);
    });

    it('narrows dashboard data to a specific month', () => {
      const res = routes.getDashboard(req({
        startDate: '2025-02-01',
        endDate: '2025-02-28',
      }));

      expect(res.status).toBe(200);
      const data = res.data!;

      // Only Feb orders (o2 and o4)
      expect(data.orderMetrics.totalOrders).toBe(2);
      expect(data.orderMetrics.totalRevenue).toBe(100);

      // Only user u2 was created in Feb
      expect(data.userMetrics.newUsersInPeriod).toBe(1);

      // Revenue time series for Feb: 28 days
      expect(data.revenueTimeSeries.dataPoints.length).toBe(28);

      // Top products: cancelled excluded, so only Beta from o2
      expect(data.topProducts.length).toBe(1);
      expect(data.topProducts[0].name).toBe('Beta');
    });
  });

  // =========================================================================
  // Specific metric queries
  // =========================================================================
  describe('Specific metric queries', () => {
    beforeEach(() => {
      userRepo.save(makeUser({ id: 'u1', role: 'admin' }));

      orderRepo.save(makeOrder({
        id: 'o1', total: 50, status: 'delivered',
        items: [{ productId: 'p1', name: 'Laptop', quantity: 1, unitPrice: 50 }],
        createdAt: new Date('2025-06-01'), updatedAt: new Date('2025-06-01'),
      }));
      orderRepo.save(makeOrder({
        id: 'o2', total: 30, status: 'confirmed',
        items: [{ productId: 'p2', name: 'Mouse', quantity: 3, unitPrice: 10 }],
        createdAt: new Date('2025-06-01'), updatedAt: new Date('2025-06-01'),
      }));
      orderRepo.save(makeOrder({
        id: 'o3', total: 100, status: 'shipped',
        items: [{ productId: 'p1', name: 'Laptop', quantity: 2, unitPrice: 50 }],
        createdAt: new Date('2025-06-15'), updatedAt: new Date('2025-06-15'),
      }));
    });

    it('order metrics reflect correct totals across the full pipeline', () => {
      const res = routes.getOrderMetrics(req({
        startDate: '2025-06-01',
        endDate: '2025-06-30',
      }));

      expect(res.status).toBe(200);
      expect(res.data!.totalOrders).toBe(3);
      expect(res.data!.totalRevenue).toBe(180);
      expect(res.data!.averageOrderValue).toBeCloseTo(60, 2);
    });

    it('revenue time series aggregates correctly by day', () => {
      const res = routes.getTimeSeries(req({
        metric: 'revenue',
        startDate: '2025-06-01',
        endDate: '2025-06-15',
        granularity: 'day',
      }));

      expect(res.status).toBe(200);
      const points = res.data!.dataPoints;
      expect(points.length).toBe(15);

      // June 1: 50 + 30 = 80
      const june1 = points.find((p) => p.date === '2025-06-01');
      expect(june1!.value).toBe(80);

      // June 15: 100
      const june15 = points.find((p) => p.date === '2025-06-15');
      expect(june15!.value).toBe(100);

      // June 2: no orders → 0
      const june2 = points.find((p) => p.date === '2025-06-02');
      expect(june2!.value).toBe(0);
    });

    it('order count time series aggregates correctly', () => {
      const res = routes.getTimeSeries(req({
        metric: 'orderCount',
        startDate: '2025-06-01',
        endDate: '2025-06-15',
        granularity: 'day',
      }));

      expect(res.status).toBe(200);
      const points = res.data!.dataPoints;
      const june1 = points.find((p) => p.date === '2025-06-01');
      expect(june1!.value).toBe(2);

      const june15 = points.find((p) => p.date === '2025-06-15');
      expect(june15!.value).toBe(1);
    });

    it('weekly granularity groups orders into week buckets', () => {
      const res = routes.getTimeSeries(req({
        metric: 'revenue',
        startDate: '2025-06-01',
        endDate: '2025-06-30',
        granularity: 'week',
      }));

      expect(res.status).toBe(200);
      const points = res.data!.dataPoints;
      // June has ~5 week buckets
      expect(points.length).toBeGreaterThanOrEqual(4);
      expect(points.length).toBeLessThanOrEqual(6);

      // Total revenue across all week buckets should be 180
      const totalRevenue = points.reduce((sum, p) => sum + p.value, 0);
      expect(totalRevenue).toBe(180);
    });

    it('monthly granularity groups all June orders into one bucket', () => {
      const res = routes.getTimeSeries(req({
        metric: 'revenue',
        startDate: '2025-06-01',
        endDate: '2025-06-30',
        granularity: 'month',
      }));

      expect(res.status).toBe(200);
      const points = res.data!.dataPoints;
      expect(points.length).toBe(1);
      expect(points[0].date).toBe('2025-06-01');
      expect(points[0].value).toBe(180);
    });

    it('top products ranks correctly with cancelled orders excluded', () => {
      // Add a cancelled order with high value
      orderRepo.save(makeOrder({
        id: 'o-cancelled', total: 500, status: 'cancelled',
        items: [{ productId: 'p3', name: 'Expensive', quantity: 10, unitPrice: 50 }],
        createdAt: new Date('2025-06-10'), updatedAt: new Date('2025-06-10'),
      }));

      const res = routes.getTopProducts(req({
        startDate: '2025-06-01',
        endDate: '2025-06-30',
      }));

      expect(res.status).toBe(200);
      // Expensive should be excluded (cancelled)
      const names = res.data!.map((p) => p.name);
      expect(names).not.toContain('Expensive');

      // Laptop: 1*50 + 2*50 = 150, Mouse: 3*10 = 30
      expect(res.data![0].name).toBe('Laptop');
      expect(res.data![0].totalRevenue).toBe(150);
      expect(res.data![1].name).toBe('Mouse');
      expect(res.data![1].totalRevenue).toBe(30);
    });

    it('top products limit restricts result count', () => {
      const res = routes.getTopProducts(req({
        startDate: '2025-06-01',
        endDate: '2025-06-30',
        limit: '1',
      }));

      expect(res.status).toBe(200);
      expect(res.data!.length).toBe(1);
      expect(res.data![0].name).toBe('Laptop');
    });
  });

  // =========================================================================
  // Time-range filtering consistency
  // =========================================================================
  describe('Time-range filtering consistency', () => {
    beforeEach(() => {
      userRepo.save(makeUser({ id: 'u1', role: 'admin', createdAt: new Date('2025-04-01'), updatedAt: new Date('2025-04-01') }));
      userRepo.save(makeUser({ id: 'u2', role: 'member', createdAt: new Date('2025-05-01'), updatedAt: new Date('2025-05-01') }));

      // Order exactly on boundary dates
      orderRepo.save(makeOrder({
        id: 'o-start', total: 10, createdAt: new Date('2025-04-01'), updatedAt: new Date('2025-04-01'),
        items: [{ productId: 'p1', name: 'A', quantity: 1, unitPrice: 10 }],
      }));
      orderRepo.save(makeOrder({
        id: 'o-end', total: 20, createdAt: new Date('2025-04-30'), updatedAt: new Date('2025-04-30'),
        items: [{ productId: 'p2', name: 'B', quantity: 1, unitPrice: 20 }],
      }));
      // Order outside range
      orderRepo.save(makeOrder({
        id: 'o-outside', total: 999, createdAt: new Date('2025-05-15'), updatedAt: new Date('2025-05-15'),
        items: [{ productId: 'p3', name: 'C', quantity: 1, unitPrice: 999 }],
      }));
    });

    it('orders on boundary dates are included', () => {
      const res = routes.getOrderMetrics(req({
        startDate: '2025-04-01',
        endDate: '2025-04-30',
      }));

      expect(res.status).toBe(200);
      expect(res.data!.totalOrders).toBe(2);
      expect(res.data!.totalRevenue).toBe(30);
    });

    it('orders outside the range are excluded', () => {
      const res = routes.getOrderMetrics(req({
        startDate: '2025-04-01',
        endDate: '2025-04-30',
      }));

      expect(res.status).toBe(200);
      expect(res.data!.totalRevenue).toBe(30); // excludes o-outside (999)
    });

    it('user metrics count new users in period correctly on boundary', () => {
      const res = routes.getUserMetrics(req({
        startDate: '2025-04-01',
        endDate: '2025-04-30',
      }));

      expect(res.status).toBe(200);
      expect(res.data!.totalUsers).toBe(2); // total is always all users
      expect(res.data!.newUsersInPeriod).toBe(1); // only u1 created in April
    });

    it('time series covers exactly the requested range', () => {
      const res = routes.getTimeSeries(req({
        metric: 'revenue',
        startDate: '2025-04-01',
        endDate: '2025-04-30',
        granularity: 'day',
      }));

      expect(res.status).toBe(200);
      expect(res.data!.dataPoints.length).toBe(30);
      expect(res.data!.startDate).toBe('2025-04-01');
      expect(res.data!.endDate).toBe('2025-04-30');

      const first = res.data!.dataPoints[0];
      expect(first.date).toBe('2025-04-01');
      expect(first.value).toBe(10);

      const last = res.data!.dataPoints[29];
      expect(last.date).toBe('2025-04-30');
      expect(last.value).toBe(20);
    });

    it('dashboard and individual endpoints agree on same date range', () => {
      const range = { startDate: '2025-04-01', endDate: '2025-04-30' };

      const dashRes = routes.getDashboard(req(range));
      const orderRes = routes.getOrderMetrics(req(range));
      const userRes = routes.getUserMetrics(req(range));
      const topRes = routes.getTopProducts(req(range));

      expect(dashRes.status).toBe(200);
      expect(orderRes.status).toBe(200);
      expect(userRes.status).toBe(200);
      expect(topRes.status).toBe(200);

      // Dashboard data should match individual endpoint results
      expect(dashRes.data!.orderMetrics).toEqual(orderRes.data!);
      expect(dashRes.data!.userMetrics).toEqual(userRes.data!);
      expect(dashRes.data!.topProducts).toEqual(topRes.data!);
    });
  });

  // =========================================================================
  // Empty data scenarios
  // =========================================================================
  describe('Empty data scenarios', () => {
    it('all endpoints handle empty database gracefully', () => {
      const orderRes = routes.getOrderMetrics(req());
      expect(orderRes.status).toBe(200);
      expect(orderRes.data!.totalOrders).toBe(0);
      expect(orderRes.data!.totalRevenue).toBe(0);
      expect(orderRes.data!.averageOrderValue).toBe(0);

      const userRes = routes.getUserMetrics(req());
      expect(userRes.status).toBe(200);
      expect(userRes.data!.totalUsers).toBe(0);

      const topRes = routes.getTopProducts(req());
      expect(topRes.status).toBe(200);
      expect(topRes.data!.length).toBe(0);
    });

    it('dashboard works with empty database', () => {
      const res = routes.getDashboard(req({
        startDate: '2025-01-01',
        endDate: '2025-01-31',
      }));

      expect(res.status).toBe(200);
      expect(res.data!.orderMetrics.totalOrders).toBe(0);
      expect(res.data!.userMetrics.totalUsers).toBe(0);
      expect(res.data!.topProducts.length).toBe(0);
      expect(res.data!.revenueTimeSeries.dataPoints.length).toBe(31);
      // All data points should be 0
      expect(res.data!.revenueTimeSeries.dataPoints.every((p) => p.value === 0)).toBe(true);
    });

    it('time series returns zeroed buckets when no orders match', () => {
      orderRepo.save(makeOrder({
        id: 'o-far', createdAt: new Date('2025-12-01'), updatedAt: new Date('2025-12-01'),
      }));

      const res = routes.getTimeSeries(req({
        metric: 'revenue',
        startDate: '2025-06-01',
        endDate: '2025-06-07',
        granularity: 'day',
      }));

      expect(res.status).toBe(200);
      expect(res.data!.dataPoints.length).toBe(7);
      expect(res.data!.dataPoints.every((p) => p.value === 0)).toBe(true);
    });
  });

  // =========================================================================
  // Error scenarios
  // =========================================================================
  describe('Error scenarios', () => {
    it('rejects invalid date formats across all endpoints', () => {
      const endpoints = [
        () => routes.getOrderMetrics(req({ startDate: 'abc' })),
        () => routes.getUserMetrics(req({ endDate: 'xyz' })),
        () => routes.getTopProducts(req({ startDate: '2025-13-45' })),
        () => routes.getTimeSeries(req({ metric: 'revenue', startDate: 'bad', endDate: '2025-01-31' })),
        () => routes.getDashboard(req({ startDate: '2025-01-01', endDate: 'nope' })),
      ];

      for (const call of endpoints) {
        const res = call();
        expect(res.status).toBe(400);
        expect(res.error).toBeDefined();
      }
    });

    it('rejects startDate after endDate across all date-validated endpoints', () => {
      const reversed = { startDate: '2025-12-01', endDate: '2025-01-01' };

      expect(routes.getOrderMetrics(req(reversed)).status).toBe(400);
      expect(routes.getUserMetrics(req(reversed)).status).toBe(400);
      expect(routes.getTopProducts(req(reversed)).status).toBe(400);
      expect(routes.getTimeSeries(req({ metric: 'revenue', ...reversed })).status).toBe(400);
      expect(routes.getDashboard(req(reversed)).status).toBe(400);
    });

    it('rejects missing required params on time series', () => {
      // Missing metric
      expect(routes.getTimeSeries(req({
        startDate: '2025-01-01', endDate: '2025-01-31',
      })).status).toBe(400);

      // Missing startDate
      expect(routes.getTimeSeries(req({
        metric: 'revenue', endDate: '2025-01-31',
      })).status).toBe(400);

      // Missing endDate
      expect(routes.getTimeSeries(req({
        metric: 'revenue', startDate: '2025-01-01',
      })).status).toBe(400);
    });

    it('rejects invalid metric values', () => {
      const res = routes.getTimeSeries(req({
        metric: 'profit',
        startDate: '2025-01-01',
        endDate: '2025-01-31',
      }));
      expect(res.status).toBe(400);
      expect(res.error).toContain('Invalid metric');
    });

    it('rejects invalid granularity values', () => {
      const res = routes.getTimeSeries(req({
        metric: 'revenue',
        startDate: '2025-01-01',
        endDate: '2025-01-31',
        granularity: 'quarter',
      }));
      expect(res.status).toBe(400);
      expect(res.error).toContain('Invalid granularity');
    });

    it('rejects non-positive limit values', () => {
      expect(routes.getTopProducts(req({ limit: '0' })).status).toBe(400);
      expect(routes.getTopProducts(req({ limit: '-5' })).status).toBe(400);
      expect(routes.getTopProducts(req({ limit: 'abc' })).status).toBe(400);
    });

    it('rejects missing required params on dashboard', () => {
      expect(routes.getDashboard(req({ endDate: '2025-01-31' })).status).toBe(400);
      expect(routes.getDashboard(req({ startDate: '2025-01-01' })).status).toBe(400);
      expect(routes.getDashboard(req()).status).toBe(400);
    });
  });

  // =========================================================================
  // Multi-product order aggregation
  // =========================================================================
  describe('Multi-product order aggregation', () => {
    beforeEach(() => {
      userRepo.save(makeUser({ id: 'u1', role: 'admin' }));

      // Order with multiple items
      orderRepo.save(makeOrder({
        id: 'o1', total: 170, status: 'delivered',
        items: [
          { productId: 'p1', name: 'Keyboard', quantity: 2, unitPrice: 35 },
          { productId: 'p2', name: 'Monitor', quantity: 1, unitPrice: 100 },
        ],
        createdAt: new Date('2025-07-01'), updatedAt: new Date('2025-07-01'),
      }));
      // Another order sharing a product
      orderRepo.save(makeOrder({
        id: 'o2', total: 70, status: 'confirmed',
        items: [
          { productId: 'p1', name: 'Keyboard', quantity: 2, unitPrice: 35 },
        ],
        createdAt: new Date('2025-07-05'), updatedAt: new Date('2025-07-05'),
      }));
    });

    it('aggregates product quantities and revenue across orders', () => {
      const res = routes.getTopProducts(req({
        startDate: '2025-07-01',
        endDate: '2025-07-31',
